def generate_dat_list(
    model, tokenizer, scorer: DATScorer, decoding: dict,
    seed_word: str, device: str = "cuda",
    n_target: int = 10, max_attempts_per_slot: int = 3,
) -> List[str]:
    """Iteratively build a 10-noun list.  At each step, we feed the current
    list as context and ask the model to continue.  Take the first valid
    noun the parser extracts; if none, retry up to `max_attempts_per_slot`
    times with a fresh sample, otherwise skip (we'll fall short of 10)."""
    words = [seed_word]
