        if not success:
            # accept any non-duplicate parsed token even if not in GloVe vocab
            cand = parse_word_list(" " + text.split("\n")[0])
            cand = [c for c in cand if c not in words]
            if cand:
                words.append(cand[0])
            else:
                break  # give up
    return words

